0434\u043e\u043a\u0441\u0430\u043b\u044c\u043d\u043e \u0437\u0432\u0443\u0447\u0430\u043b\u043e. \u042d\u0442\u043e \u043e\u0431\u0443\u0441\u043b\u043e\u0432\u043b\u0435\u043d\u043e \u043f\u0440\u043e\u0434\u0443\u043c\u0430\u043d\u043d\u043e\u0439 \u043b\u043e\u0433\u0438\u0441\u0442\u0438\u043a\u043e\u0439, \u0443\u0440\u043e\u0432\u043d\u0435\u043c \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044f \u0441\u0435\u0440\u0432\u0438\u0441\u043e\u0432 \u043f\u043e \u043e\u0446\u0435\u043d\u043a\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f \u0430\u0432\u0442\u043e \u0438 \u0441\u0430\u043c\u0438\u043c \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u043c \u043f\u043e\u043a\u0443\u043f\u043a\u0438 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f.<\/span><\/font><\/p><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><span style=\"font-size: 14px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif;\">\u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0433\u0440\u0430\u0436\u0434\u0430\u043d \u0421\u0428\u0410 \u0431\u0435\u0440\u0443\u0442 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u0432 \u043b\u0438\u0437\u0438\u043d\u0433 \u043d\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043b\u0435\u0442 \u0438 \u0432\u0441\u0435 \u0432\u0440\u0435\u043c\u044f \u044d\u043a\u0441\u043f\u043b\u0443\u0430\u0442\u0430\u0446\u0438\u0438 \u0441\u0430\u043c\u0430 \u043b\u0438\u0437\u0438\u043d\u0433\u043e\u0432\u0430\u044f \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442\u0441\u044f \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u044b\u043c \u0422\u041e \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f, \u0432 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0435 \u0447\u0435\u0433\u043e \u043c\u0430\u0448\u0438\u043d\u044b \u0438\u0437 \u0421\u0428\u0410 \u2013 \u043e\u0434\u0438\u043d \u0438\u0437 \u043b\u0443\u0447\u0448\u0438\u0445 \u0432\u044b\u0431\u043e\u0440\u043e\u0432 \u0434\u043b\u044f \u0430\u0432\u0442\u043e\u043b\u044e\u0431\u0438\u0442\u0435\u043b\u0435\u0439 \u0423\u043a\u0440\u0430\u0438\u043d\u044b.<\/span><\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041f\u043e\u0447\u0435\u043c\u0443 \u0442\u0430\u043a\u0430\u044f \u043d\u0438\u0437\u043a\u0430\u044f \u0446\u0435\u043d\u0430?<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-size: 14px; outline: 0px;\">\u0411\u0438\u0442\u044b\u0435 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0438 \u0438\u0437 \u0421\u0428\u0410 \u0432\u044b\u043a\u0443\u043f\u0430\u044e\u0442\u0441\u044f \u0441 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u043e\u0432 \u0441\u0442\u0440\u0430\u0445\u043e\u0432\u044b\u0445 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0439. \u041d\u0430 \u044d\u0442\u0438\u0445 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0430\u0445 \u043c\u0430\u0448\u0438\u043d\u0430 \u0442\u0435\u0440\u044f\u0435\u0442 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0443 \u0446\u0435\u043d\u044b \u0434\u0430\u0436\u0435 \u0438\u0437-\u0437\u0430 \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u043e\u0432\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u0439. \u0415\u0441\u043b\u0438 \u0443\u0447\u0438\u0442\u044b\u0432\u0430\u0442\u044c \u0434\u0435\u043d\u0435\u0436\u043d\u044b\u0435 \u0440\u0430\u0441\u0445\u043e\u0434\u044b, \u0430 \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u044b\u043a\u0443\u043f, \u0434\u043e\u0441\u0442\u0430\u0432\u043a\u0443, \u0442\u0430\u043c\u043e\u0436\u043d\u044e \u0438 \u0440\u0435\u043c\u043e\u043d\u0442, \u0446\u0435\u043d\u0430 \u0430\u043d\u0430\u043b\u043e\u0433\u0438\u0447\u043d\u043e\u0433\u043e \u043f\u043e \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044e \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0435 \u0431\u0443\u0434\u0435\u0442 \u0432\u044b\u0448\u0435 \u043d\u0430 35-50%, \u0430 \u043d\u043e\u0432\u044b\u0435 \u0431\u0443\u0434\u0443\u0442 \u0441\u0442\u043e\u0438\u0442\u044c \u043a\u043e\u0441\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0434\u0435\u043d\u0435\u0433.<\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041a\u043e\u043c\u043f\u043b\u0435\u043a\u0442\u0430\u0446\u0438\u0438 \u0435\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u043a\u0438\u0445 \u0438 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u0445 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-size: 14px; outline: 0px;\">\u041e\u0442\u043b\u0438\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0447\u0435\u0440\u0442\u0430 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439 \u0438\u0437 \u0421\u0428\u0410 \u2013 \u043f\u0440\u0435\u043e\u0431\u043b\u0430\u0434\u0430\u043d\u0438\u0435 \u043f\u043e\u043b\u043d\u043e\u0439 \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0442\u0430\u0446\u0438\u0438 \u043d\u0430\u0434 \u0431\u0430\u0437\u043e\u0432\u043e\u0439. \u041f\u043e\u044d\u0442\u043e\u043c\u0443 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u0432 \u00ab\u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u043a\u0435\u00bb \u0431\u0443\u0434\u0435\u0442 \u0441\u0442\u043e\u0438\u0442\u044c \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0434\u043e\u0440\u043e\u0436\u0435 \u00ab\u043f\u0443\u0441\u0442\u043e\u0433\u043e\u00bb \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0441\u0430\u043c\u043e\u0435 \u0432\u044b\u0433\u043e\u0434\u043d\u043e\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u2013 \u043f\u043e\u043a\u0443\u043f\u043a\u0430 \u043c\u0430\u0448\u0438\u043d\u044b \u0438\u0437 \u0421\u0428\u0410 \u0432 \u00ab\u043f\u043e\u043b\u043d\u043e\u043c \u0444\u0430\u0440\u0448\u0435\u00bb. \u0411\u043e\u043b\u0435\u0435 \u043f\u043e\u0434\u0440\u043e\u0431\u043d\u043e \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c \u0432 \u043d\u0430\u0448\u0435\u0439 \u0441\u0442\u0430\u0442\u044c\u0435 \u2013 \"\u041e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u043e\u0442\u043b\u0438\u0447\u0438\u044f \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u0445 \u0430\u0432\u0442\u043e \u043e\u0442 \u0435\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u043a\u0438\u0445\".<\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041f\u0440\u043e\u0431\u0435\u0433<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-size: 14px; outline: 0px;\">\u041c\u044b \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u044c\u043d\u043e \u043f\u043e\u0434\u0431\u0438\u0440\u0430\u0435\u043c \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0438 \u0438\u0437 \u0410\u043c\u0435\u0440\u0438\u043a\u0438 \u043d\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0430\u0445 \u0441 \u043d\u0438\u0437\u043a\u0438\u043c \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0435\u043c \u043f\u0440\u043e\u0431\u0435\u0433\u0430. \u042d\u0442\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u0432\u0430\u043c \u0432 \u0434\u0430\u043b\u044c\u043d\u0435\u0439\u0448\u0435\u043c \u044f\u0441\u043d\u043e \u043f\u043e\u043d\u0438\u043c\u0430\u0442\u044c, \u043a\u0430\u043a \u0431\u0443\u0434\u0435\u0442 \u0432\u0435\u0441\u0442\u0438 \u0441\u0435\u0431\u044f \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u043d\u0430 \u0434\u0438\u0441\u0442\u0430\u043d\u0446\u0438\u0438 \u0432 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043b\u0435\u0442.<\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041e\u0431\u0441\u043b\u0443\u0436\u0438\u0432\u0430\u043d\u0438\u0435<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-size: 14px; outline: 0px;\">\u0421\u0444\u0435\u0440\u0430 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c\u043d\u043e\u0433\u043e \u043e\u0431\u0441\u043b\u0443\u0436\u0438\u0432\u0430\u043d\u0438\u044f \u0432 \u0410\u043c\u0435\u0440\u0438\u043a\u0435 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u043b\u0430\u0441\u044c \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u043c\u0438\u0440\u043e\u0432\u044b\u043c \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0441\u0442\u0440\u043e\u0435\u043d\u0438\u0435\u043c. \u0412\u0441\u0435 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0446\u044b \u0447\u0435\u0441\u0442\u043d\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0442 \u0422\u041e, \u0438 \u0437\u0430\u043f\u0438\u0441\u0438 \u043e\u0431 \u044d\u0442\u043e\u043c \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f \u0432 \u0431\u0430\u0437\u0435, \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u043f\u043e\u0447\u0442\u0438 \u0441\u043e \u0441\u0442\u043e\u043f\u0440\u043e\u0446\u0435\u043d\u0442\u043d\u043e\u0439 \u0432\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0441\u0442\u044c\u044e \u0431\u0443\u0434\u0435\u0442 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438\u0440\u0443\u0435\u043c\u044b\u043c. \u041f\u0440\u043e\u0434\u0430\u0436\u0430 \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442 \u0431\u0435\u0437 \u043f\u043e\u0441\u0440\u0435\u0434\u043d\u0438\u043a\u043e\u0432.<\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041c\u043e\u0434\u0435\u043b\u044c\u043d\u044b\u0439 \u0440\u044f\u0434<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-size: 14px; outline: 0px;\">\u0410\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0446\u044b \u0435\u0436\u0435\u0433\u043e\u0434\u043d\u043e \u043f\u0440\u043e\u0434\u0430\u044e\u0442 \u0441\u043e\u0442\u043d\u0438 \u0442\u044b\u0441\u044f\u0447 \u043b\u0438\u0447\u043d\u044b\u0445 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439 \u0440\u0430\u0437\u043d\u044b\u0445 \u043c\u0430\u0440\u043e\u043a \u043d\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0430\u0445 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439 \u0432 \u0421\u0428\u0410.<\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u0420\u0430\u0431\u043e\u0442\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u043e\u0432 \u0441 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u043c\u0438 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f\u043c\u0438:<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u041f\u043e\u0441\u043b\u0435 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u044f \u0434\u043e\u0441\u0442\u0443\u043f\u0430 \u043a \u0442\u043e\u0440\u0433\u0430\u043c \u043d\u0430\u0448 \u0441\u043e\u0442\u0440\u0443\u0434\u043d\u0438\u043a \u0434\u0435\u043b\u0430\u0435\u0442 \u0441\u0442\u0430\u0432\u043a\u0443 \u043d\u0430 \u0432\u044b\u043a\u0443\u043f \u043c\u0430\u0448\u0438\u043d\u044b.<\/span><\/font><\/p><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u0410\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u0434\u043e\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u0442\u043e\u043c\u0443, \u0447\u044c\u044f \u0441\u0442\u0430\u0432\u043a\u0430 \u0431\u0443\u0434\u0435\u0442 \u0432\u044b\u0448\u0435 \u0434\u0440\u0443\u0433\u0438\u0445. \u0415\u0441\u043b\u0438 \u0441\u0442\u0430\u0432\u043a\u0430 \u0437\u0430\u0448\u043b\u0430, \u0442\u043e \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0441\u044f \u0441\u043b\u043e\u0436\u043d\u044b\u0439 \u043f\u0440\u043e\u0446\u0435\u0441\u0441 \u043f\u043e\u043b\u0443\u0447\u0435\u043d\u0438\u044f \u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u043e\u0432 \u043d\u0430 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c, \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0430 \u043f\u043b\u043e\u0449\u0430\u0434\u043a\u0443 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 \u0432 \u0421\u0428\u0410, \u0437\u0430\u0442\u0435\u043c \u0432 \u043f\u043e\u0440\u0442 \u0438 \u0434\u0430\u043b\u044c\u0448\u0435 \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0443.<\/span><\/font><\/p><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u0427\u0442\u043e \u043d\u0443\u0436\u043d\u043e \u043a\u043b\u0438\u0435\u043d\u0442\u0443? \u0412\u0430\u043c \u043d\u0443\u0436\u043d\u043e \u043e\u0431\u044a\u044f\u0432\u0438\u0442\u044c \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u0443\u044e \u0441\u0442\u043e\u0438\u043c\u043e\u0441\u0442\u044c \u0432\u044b\u043a\u0443\u043f\u0430 \u043c\u0430\u0448\u0438\u043d\u044b (\u044d\u0442\u043e\u0442 \u043c\u043e\u043c\u0435\u043d\u0442 \u043e\u0431\u0441\u0443\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u0435\u0449\u0435 \u0434\u043e \u0442\u043e\u0440\u0433\u043e\u0432 \u043d\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0435, \u0438\u0441\u0445\u043e\u0434\u044f \u0438\u0437 \u043f\u0440\u043e\u0433\u043d\u043e\u0437\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0446\u0435\u043d\u044b \u043d\u0430 \u0442\u043e\u0440\u0433\u0430\u0445, \u043f\u0440\u043e\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u00ab\u043f\u043e\u0434 \u043a\u043b\u044e\u0447\u00bb \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0435).<\/span><\/font><\/p><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u0414\u0430\u043b\u0435\u0435 \u043c\u0430\u0448\u0438\u043d\u0430 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432 \u043f\u043b\u0430\u0432\u0430\u043d\u0438\u0435 \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0443. \u0412\u0440\u0435\u043c\u044f \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u0431\u044b\u0432\u0430\u0435\u0442 \u043d\u0435 \u0431\u043e\u043b\u044c\u0448\u0435 10 \u043d\u0435\u0434\u0435\u043b\u044c \u0441 \u043c\u043e\u043c\u0435\u043d\u0442\u0430 \u0432\u044b\u0438\u0433\u0440\u044b\u0448\u0430 \u0438 \u043e\u0444\u043e\u0440\u043c\u043b\u0435\u043d\u0438\u044f \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f.<\/span><\/font><\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041e\u0441\u043e\u0431\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0442\u043e\u0440\u0433\u043e\u0432 \u043d\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u043e\u0432<\/h3><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u041a\u0430\u043a \u0443\u0436\u0435 \u0433\u043e\u0432\u043e\u0440\u0438\u043b\u043e\u0441\u044c \u0432\u044b\u0448\u0435, \u0434\u043b\u044f \u0443\u0447\u0430\u0441\u0442\u0438\u044f \u0432 \u0442\u043e\u0440\u0433\u0430\u0445 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0434\u043e\u043b\u0436\u0435\u043d \u0438\u043c\u0435\u0442\u044c \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u043e\u043a\u0443\u043f\u043a\u0430 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f \u043f\u043e \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0443 \u0432 \u0421\u0428\u0410 \u0434\u043b\u044f \u0440\u044f\u0434\u043e\u0432\u043e\u0433\u043e \u0433\u0440\u0430\u0436\u0434\u0430\u043d\u0438\u043d\u0430 \u0423\u043a\u0440\u0430\u0438\u043d\u044b \u0431\u0443\u0434\u0435\u0442 \u043d\u0435\u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\u0439, \u043d\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0435 \u0434\u043b\u044f \u043d\u0430\u0441. \u041a\u043e\u043c\u043f\u0430\u043d\u0438\u044f Bexhill Trading Auto \u043f\u043e\u043b\u0443\u0447\u0438\u043b\u0430 \u0434\u043e\u0441\u0442\u0443\u043f \u043a \u043e\u0442\u043a\u0440\u044b\u0442\u044b\u043c \u0438 \u0437\u0430\u043a\u0440\u044b\u0442\u044b\u043c \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0430\u043c, \u0447\u0442\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u043a\u0443\u043f\u0438\u0442\u044c \u0430\u0432\u0442\u043e \u0438\u0437 \u0421\u0428\u0410, \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u0443\u044f\u0441\u044c \u043d\u0430 \u043f\u0440\u0435\u0438\u043c\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043a\u043b\u0438\u0435\u043d\u0442\u0430 \u0438 \u043e\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043b\u044f\u0442\u044c \u043f\u0440\u0438\u0433\u043e\u043d \u0430\u0432\u0442\u043e \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0435 \u043f\u043e\u0434 \u0437\u0430\u043a\u0430\u0437.<\/span><\/font><\/p><p style=\"margin-right: 0px; margin-bottom: 30px; margin-left: 0px; outline: 0px;\"><font color=\"#333333\" face=\"Montserrat, sans-serif\"><span style=\"font-size: 14px;\">\u041d\u0430\u0448\u0438 \u043a\u043b\u0438\u0435\u043d\u0442\u044b \u0437\u0430\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044c \u0438\u0437 \u0421\u043e\u0435\u0434\u0438\u043d\u0435\u043d\u043d\u044b\u0445 \u0448\u0442\u0430\u0442\u043e\u0432 \u0410\u043c\u0435\u0440\u0438\u043a\u0438 \u043f\u043e \u0446\u0435\u043d\u0435 \u043d\u0430 35-50% \u043d\u0438\u0436\u0435 \u0440\u044b\u043d\u043e\u0447\u043d\u043e\u0439. \u041d\u0430 \u0430\u0443\u043a\u0446\u0438\u043e\u043d\u0430\u0445 \u0435\u0436\u0435\u043d\u0435\u0434\u0435\u043b\u044c\u043d\u043e \u0440\u0435\u0430\u043b\u0438\u0437\u0443\u044e\u0442\u0441\u044f \u0442\u044b\u0441\u044f\u0447\u0438 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u0435\u0439 \u0441\u0442\u0440\u0430\u0445\u043e\u0432\u044b\u0445 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0439, \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0434\u0438\u0437\u0435\u043b\u044c\u043d\u044b\u0435, \u0431\u0435\u043d\u0437\u0438\u043d\u043e\u0432\u044b\u0435, \u0433\u0438\u0431\u0440\u0438\u0434\u044b \u0438 \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043c\u043e\u0431\u0438\u043b\u0438. \u041c\u044b \u043c\u043e\u0436\u0435\u043c \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u043e\u0432\u0430\u0442\u044c \u0442\u0440\u0430\u043d\u0441\u043f\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u0430\u0432\u0442\u043e\u043c\u043e\u0431\u0438\u043b\u044f \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u0423\u043a\u0440\u0430\u0438\u043d\u0443, \u043d\u043e \u0438 \u043f\u043e \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0438 \u0423\u043a\u0440\u0430\u0438\u043d\u044b (\u043a\u0440\u043e\u043c\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u043e\u043a\u043a\u0443\u043f\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0439 \u0414\u043e\u043d\u0435\u0446\u043a\u043e\u0439 \u0438 \u041b\u0443\u0433\u0430\u043d\u0441\u043a\u043e\u0439 \u043e\u0431\u043b\u0430\u0441\u0442\u0438, \u0438 \u0410\u0420 \u041a\u0440\u044b\u043c).<\/span><\/font><\/p><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat, sans-serif; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-caps: small-caps; outline: 0px;\">\u041f\u043e\u0447\u0435\u043c\u0443 \u043c\u044b?<\/h3><h3 style=\"margin-right: 0px; margin-bottom: 24px; margin-left: 0px; font-weight: 600; line-height: 43px; font-size: 36px; color: rgb(51, 51, 51); font-family: Montserrat